final:
module comparator_4bit(
    input wire [3:0] cmp_A,
    input wire [3:0] B,
    output wire A_greater,
    output wire A_equal,
    output wire A_less
    );

assign A_greater = (cmp_A > B) ? 1'b1 : 1'b0;
assign A_equal = (cmp_A == B) ? 1'b1 : 1'b0;
assign A_less = (cmp_A < B) ? 1'b1 : 1'b0;

endmodule
